function buildIntroStats(){
  try{
    const L=ST.diagLang||'ko';
    const m=DATA.months[DATA.months.length-1];
    const recs=DATA.records.filter(r=>r.month===m);
    const nChurch=recs.filter(r=>r.gubun==="교회").length;
    const nRegion=recs.filter(r=>r.gubun==="지역").length;
    const nPion=recs.filter(r=>r.gubun==="개척지").length;
    const nCountry=new Set(recs.map(r=>r.country).filter(c=>c&&c!=="-")).size;
    const nJipa=(DATA.jipaOrder||[]).length;
    const u=UI_TR.unit[L];
    const stats=[[UI_TR.stChurch[L],nChurch+u],[UI_TR.stRegion[L],nRegion+u],[UI_TR.stPion[L],nPion+u]];
    const el=document.getElementById("introStats");
    if(el) el.innerHTML=stats.map(s=>`<div class="in-stat"><b>${s[1]}</b><span>${s[0]}</span></div>`).join("")
      + `<div class="in-stat"><b>${nCountry}<i class="u">${UI_TR.suffCountry[L]}</i></b><span>${nJipa}${UI_TR.suffJipa[L]}</span></div>`;
  }catch(e){}
}
function applyStaticLang(){
  const L=ST.diagLang||'ko';
  const set=(id,html)=>{const e=document.getElementById(id); if(e)e.innerHTML=html;};
  set('inTitle',UI_TR.title[L]); set('inMission',UI_TR.mission[L]);
  const f=document.getElementById('introFoot'); if(f)f.textContent='';
  const pw=document.getElementById('introPw'); if(pw)pw.placeholder=UI_TR.pw[L];
  set('introEnter',UI_TR.enter[L]); set('tbBrand',UI_TR.brand[L]);
  set('moLabel',UI_TR.moLabel[L]); set('btnCover',UI_TR.cover[L]); set('btnPrint',UI_TR.print[L]);
  buildIntroStats();
  document.querySelectorAll('.langSel').forEach(s=>{s.value=L;});
  document.documentElement.lang=(L==='ko'?'ko':L);
}
function setLang(l){ ST.diagLang=l; applyStaticLang(); if(typeof renderDiag==='function') renderDiag(); }
