const CAT_NAMES = Object.keys(CATS);
const VIEWS = ["🚨 점검(양·질)","🔬 전환율","대륙별","지파별","교회별","지역별","개척지별","📈 지파 추이"];

function getMonthNumFromStr(mStr) {
  if (!mStr) return 0;
  const match = String(mStr).match(/(\d+)월/);
  return match ? parseInt(match[1]) : parseInt(mStr) || 0;
}
function getYearNumFromStr(mStr) {
  if (!mStr) return 2026;
  const match = String(mStr).match(/(\d+)년/);
  return match ? parseInt(match[1]) : 2026;
}

// sum numeric fields across a set of records
const SUM_FIELDS = ["yearStartReg","retroReg","prevReg","newAdmit","transIn","transOut","moveIn","moveOut",
  "discipline","dupReg","registered","regChange","cumNewAdmit","cumDiscipline","prevNewAdmitCnt",
  "newAttOnsite","newAttOnline","newAttEtc","newAttTotal","attReg","attOnsite","attOnline","attEtc",
  "attTotal","absTotal","evangReg","bibleMonthReg","bibleCumReg","bibleCurAtt","centerMonthOn",
  "centerMonthOff","centerMonthTotal","centerTotMonthReg","centerCumOn","centerCumOff","centerCumReg","centerTotCumReg","centerMonthGrad","centerCumGrad","centerAttElem",
  "centerAttMid","centerAttHigh","absOnce","absLongManage","absLongUnmanage"];
function aggregate(recs){
  const o={count:recs.length}; SUM_FIELDS.forEach(f=>o[f]=0);
  o.ctwkE=0; o.ctwkM=0; o.ctwkH=0; o.catE=0; o.catM=0; o.catH=0; // 센터 초/중/고 총등록·출석(주간보고서 매칭분) — 출석율 분자·분모 동일집합(리더 확정 2026-07-04)
  recs.forEach(r=>{ SUM_FIELDS.forEach(f=>o[f]+=(+r[f]||0)); const c=(typeof CENTERWK!=='undefined')?CENTERWK[r.name]:null; if(c){o.ctwkE+=c[0];o.ctwkM+=c[1];o.ctwkH+=c[2]; o.catE+=(+c[3]||0);o.catM+=(+c[4]||0);o.catH+=(+c[5]||0);} }); // 출석도 CENTERWK(주간보고서 c[3~5])에서 — 지파통계 시트와 100%일치(리더 확정 2026-07-04)
  return o;
}
function metricVal(row,m){ return (typeof m.k==="function")? m.k(row) : row[m.k]; }
function fmtVal(v,m){ if(v==null||isNaN(v)) return "-"; return m.t==="pct"? pct(v) : ((m.signed&&v>0?"+":"")+fmt(v)); }

// ── state ──
const ST = {section:"diag", month:null, gubun:"전체", view:"교회별", group:"지파별", cat:"①전도", sortIdx:null, sortDir:-1, mode:"data", cmp:"first", lastDetail:null, trendMetric:null, trendMonths:null, inspX:"ascore", inspY:"qscore", inspOpen:{std:false,low:false,best:false,fb:false,held:false}, funOpen:{}, trendMetrics:null, trendStack:false};

function checkAssignedLocationAccess(r){
  try {
    const userStr = localStorage.getItem('user');
    if (!userStr) return true;
    const u = JSON.parse(userStr);
    const role = u.role || 'ROLE_USER';
    const assignedLocation = u.assignedCountry || '전체';

    if (role === 'ROLE_ADMIN' || role === 'ADMIN' || role === '관리자' || assignedLocation === '전체') {
      return true;
    }

    const name = r.name || '';
    const country = r.country || '';
    const jipaName = (r.jipa ? r.jipa + ' · ' : '') + name;

    return name === assignedLocation ||
           country === assignedLocation ||
           jipaName === assignedLocation ||
           assignedLocation.includes(name) ||
           name.includes(assignedLocation);
  } catch(e) {
    return true;
  }
}

function recordsFor(month, gubunFilter){
  return DATA.records.filter(r=> r.month===month && (gubunFilter==="전체" || r.gubun===gubunFilter) && checkAssignedLocationAccess(r));
}

// build grouped rows for current view
function buildRows(){
  // 구분(ST.gubun: 전체/교회/지역/개척지)으로 필터 → 묶음(ST.group: 개별/지파별/대륙별)으로 그룹화
  const recs = recordsFor(ST.month, ST.gubun);
  let groups=[];
  if(ST.group==="대륙별"){
    const map={};
    recs.forEach(r=>{ const k=contOf(r); (map[k]=map[k]||[]).push(r); });
    groups=Object.entries(map).map(([k,v])=>({name:k, color:CONT_COLORS[k]||"#888", agg:aggregate(v), kind:"continent"}));
  } else if(ST.group==="지파별"){
    DATA.jipaOrder.forEach(j=>{
      const v=recs.filter(r=>r.jipa===j);
      groups.push({name:j, color:DATA.jipaColors[j]||"#888", agg:aggregate(v), kind:"jipa"});
    });
  } else { // 개별 (개별 대상)
    recs.forEach(r=>{
      if(r.gubun==="폐쇄") return; // 폐쇄지역(소급 잔여만 반영)은 개별 목록·차트에서 숨김 — 총계엔 포함
      groups.push({name:r.name, color:DATA.jipaColors[r.jipa]||"#888", jipa:r.jipa,
        continent:CONT_KO[r.continent]||r.continent, agg:aggregate([r]), kind:"entity", rec:r});
    });
  }
  return groups.filter(g=>g.agg.count>0);
}

// ── KPI ──
function renderKPI(){
  const recs=recordsFor(ST.month, ST.gubun);
  const a=aggregate(recs);
  const nChurch=recs.filter(r=>r.gubun==="교회").length;
  const nRegion=recs.filter(r=>r.gubun==="지역").length;
  const nPion=recs.filter(r=>r.gubun==="개척지").length;
  const pctS=v=>(v==null||isNaN(v))?"-":((v>0?"+":"")+(v*100).toFixed(1)+"%");
  const sgn=v=>(v>0?"+":"")+fmt(v);
  // 비율 (분모는 리더 확정/추정 — 재적증가율=÷전월재적, 입교율=÷소급적용재적, 센터등록율=÷전도재적, 종강율=÷누적등록)
  const regDiff=a.registered-a.prevReg;
  const regRate=rate(regDiff,a.retroReg);
  const admitRate=rate(a.newAdmit,a.retroReg);
  const cumAdmitRate=rate(a.cumNewAdmit,a.retroReg);
  const newAttRate=rate(a.newAttTotal,a.prevNewAdmitCnt);
  const attRate=rate(a.attTotal,a.attReg);
  const cenRegRate=rate(a.centerCumReg,a.evangReg);
  const cenGradRate=rate(a.centerCumGrad,a.centerTotCumReg);
  const monRegRate=rate(a.centerMonthTotal,a.evangReg);
  const monGradRate=rate(a.centerMonthGrad,a.centerTotMonthReg);
  const longMng=a.absLongManage, longUn=a.absLongUnmanage;
  const kpis=[
    {l:"대상 (교회/지역/개척지)", v:`${nChurch} / ${nRegion} / ${nPion}`, s:`합계 ${nChurch+nRegion+nPion}곳`, c:"var(--gold)", ic:"🏛️"},
    {l:"총 현재적", v:fmt(a.registered), side:pctS(regRate), s:`전월 ${fmt(a.prevReg)} 대비 ${sgn(regDiff)}`, c:"#00a0e9", ic:"👥"},
    {l:"당월 입교", v:fmt(a.newAdmit), side:pct(admitRate), s:`누적입교수 ${fmt(a.cumNewAdmit)} · 누적입교율 ${pct(cumAdmitRate)}`, c:"#2ecc71", ic:"🌱"},
    {l:"전월입교자 예배 총출석", v:fmt(a.newAttTotal), side:pct(newAttRate), s:`전월입교자 ${fmt(a.prevNewAdmitCnt)}명`, c:"#e39300", ic:"🙏"},
    {l:"전성도 예배 출석율", v:pct(attRate), s:`출결재적 ${fmt(a.attReg)} · 출석 ${fmt(a.attTotal)}`, c:"#16b9c9", ic:"⛪"},
    {l:"센터 누적등록수", v:fmt(a.centerCumReg), side:pct(cenRegRate), s:`월등록 ${fmt(a.centerMonthTotal)} · 월등록율 ${pct(monRegRate)}`, c:"#7f1084", ic:"📚"},
    {l:"센터 누적종강수", v:fmt(a.centerCumGrad), side:pct(cenGradRate), s:`월종강 ${fmt(a.centerMonthGrad)} · 월종강율 ${pct(monGradRate)}`, c:"#d7005b", ic:"🎓"},
    {l:"장기결석 관리대상", v:fmt(longMng+longUn), s:`관리가능 ${fmt(longMng)} · 관리불가 ${fmt(longUn)}`, c:"#e74c3c", ic:"⚠️"},
  ];
  document.getElementById("kpis").innerHTML=kpis.map(k=>
    `<div class="kpi"><div class="k-bar" style="background:${k.c}"></div>
     <div class="k-l">${k.l}</div>
     <div class="k-v">${k.v}${k.side?`<span class="k-side" style="${k.sideCol?`color:${k.sideCol}`:''}">${k.side}</span>`:''}</div>
     <div class="k-s">${k.s}</div></div>`).join("");
}

// ── bar chart (primary metric) ──
function renderBars(rows){
  const cat=CATS[ST.cat];
  const pm=cat.find(m=>m.primary)||cat[0];
  document.getElementById("barTtl").textContent=`${ST.group==="개별"?(ST.gubun==="전체"?"대상":ST.gubun):ST.group} · ${pm.l} 순위`;
  document.getElementById("barDesc").textContent=`${ST.cat} 영역 대표 지표 기준 · 막대를 클릭하면 상세를 봅니다.`;
  const data=rows.map(g=>({...g, val:metricVal(g.agg,pm)})).filter(g=>g.val!=null)
    .sort((a,b)=>b.val-a.val);
  const max=Math.max(1,...data.map(d=>Math.abs(d.val)));
  document.getElementById("bars").innerHTML=data.map(d=>{
    const w=Math.max(2,Math.abs(d.val)/max*100);
    return `<div class="brow" data-name="${encodeURIComponent(d.name)}">
      <div class="bname" title="${d.name}"><span class="dot" style="background:${d.color}"></span>${d.name}</div>
      <div class="btrack"><div class="bfill" style="width:${w}%;background:${d.color}"></div></div>
      <div class="bval">${fmtVal(d.val,pm)}</div></div>`;
  }).join("");
  document.querySelectorAll(".brow").forEach(el=>el.onclick=()=>openDetail(decodeURIComponent(el.dataset.name)));
}

// ── table ──
function renderTable(rows){
  const cat=CATS[ST.cat];
  const cols=[{l:(ST.group==="개별"?(ST.gubun==="전체"?"대상":ST.gubun):ST.group.replace("별","")), name:true}, ...cat.map(m=>({l:m.l, m}))];
  if(ST.sortIdx==null){ ST.sortIdx=1; ST.sortDir=-1; }
  let data=rows.map(g=>({g, cells:cat.map(m=>metricVal(g.agg,m))}));
  const si=ST.sortIdx;
  data.sort((a,b)=>{
    let va,vb;
    if(si===0){ va=a.g.name; vb=b.g.name; return ST.sortDir*(""+va).localeCompare(""+vb,"ko"); }
    va=a.cells[si-1]; vb=b.cells[si-1]; va=(va==null?-Infinity:va); vb=(vb==null?-Infinity:vb);
    return ST.sortDir*(va-vb);
  });
  let html="<thead><tr>"+cols.map((c,i)=>{
    const arrow = (i===si)? (ST.sortDir<0?" ▼":" ▲") : "";
    return `<th data-i="${i}">${c.l}${arrow}</th>`;
  }).join("")+"</tr></thead><tbody>";
  html+=data.map(d=>{
    const g=d.g;
    const sub = g.kind==="entity"? `<div style="font-size:11px;color:var(--muted)">${g.jipa} · ${g.continent||"-"} · ${(g.rec&&g.rec.country)||"-"}</div>`:"";
    return `<tr class="clk" data-name="${encodeURIComponent(g.name)}">
      <td class="name"><span class="dot" style="background:${g.color}"></span>${g.name}${sub}</td>`+
      cat.map((m,j)=>{ const v=d.cells[j]; const cls=m.signed?(v>0?"pos":(v<0?"neg":"")):"";
        return `<td class="${cls}">${fmtVal(v,m)}</td>`; }).join("")+`</tr>`;
  }).join("")+"</tbody>";
  const t=document.getElementById("tbl"); t.innerHTML=html;
  t.querySelectorAll("th").forEach(th=>th.onclick=()=>{
    const i=+th.dataset.i; if(ST.sortIdx===i){ST.sortDir*=-1;} else {ST.sortIdx=i; ST.sortDir=(i===0?1:-1);} render();
  });
  t.querySelectorAll("tr.clk").forEach(tr=>tr.onclick=()=>openDetail(decodeURIComponent(tr.dataset.name)));
}

// ── detail modal ──
function seriesFor(name){
  // returns {gubun,jipa,continent,country, perMonth:{month->agg}}
  const recs=DATA.records.filter(r=>r.name===name);
  const info=recs[0]||{};
  const perMonth={};
  DATA.months.forEach(mn=>{ perMonth[mn]=aggregate(recs.filter(r=>r.month===mn)); });
  return {info, perMonth};
}
function jipaListForName(name){
  const s=new Set(DATA.records.filter(r=>r.name===name).map(r=>r.jipa)); return [...s];
}
function miniTrend(series,monthsArr,color,type,curMonth,baseMonth){
  const n=series.length;
  if(n===0) return `<div style="font-size:10.5px;color:var(--muted);margin-top:8px;text-align:center">데이터 없음</div>`;
  const vals=series.map(x=>(x==null||isNaN(x))?0:x);
  const months=monthsArr;
  const curIdx=months.indexOf(curMonth), baseIdx=months.indexOf(baseMonth);
  const max=Math.max(...vals), min=Math.min(...vals); const range=(max-min)||1;
  const W=164,H=78, PL=24,PR=8,PT=8,PB=18, plotW=W-PL-PR, plotH=H-PT-PB;
  const X=i=> PL+(n<=1?plotW/2:(i/(n-1))*plotW);
  const Y=v=> PT+plotH-((v-min)/range)*plotH;
  let grid=""; for(let k=0;k<=2;k++){ const gy=(PT+plotH*k/2).toFixed(1); grid+=`<line x1="${PL}" y1="${gy}" x2="${W-PR}" y2="${gy}" stroke="rgba(255,255,255,.07)" stroke-width="0.6"/>`; }
  const axes=`<line x1="${PL}" y1="${PT}" x2="${PL}" y2="${PT+plotH}" stroke="rgba(255,255,255,.28)" stroke-width="0.8"/><line x1="${PL}" y1="${PT+plotH}" x2="${W-PR}" y2="${PT+plotH}" stroke="rgba(255,255,255,.28)" stroke-width="0.8"/>`;
  let marker="";
  if(baseIdx!=null && baseIdx>=0 && baseIdx<n) marker+=`<line x1="${X(baseIdx).toFixed(1)}" y1="${PT}" x2="${X(baseIdx).toFixed(1)}" y2="${PT+plotH}" stroke="#8aa0c4" stroke-width="0.7" stroke-dasharray="2 2" opacity="0.45"/>`;
  if(curIdx>=0 && curIdx<n) marker+=`<line x1="${X(curIdx).toFixed(1)}" y1="${PT}" x2="${X(curIdx).toFixed(1)}" y2="${PT+plotH}" stroke="${color}" stroke-width="0.9" stroke-dasharray="2 2" opacity="0.55"/>`;
  const linePts=vals.map((v,i)=>`${X(i).toFixed(1)},${Y(v).toFixed(1)}`).join(" ");
  const areaPts=`${PL},${(PT+plotH).toFixed(1)} ${linePts} ${(W-PR).toFixed(1)},${(PT+plotH).toFixed(1)}`;
  const dots=vals.map((v,i)=>`<circle cx="${X(i).toFixed(1)}" cy="${Y(v).toFixed(1)}" r="${i===curIdx?3.4:1.9}" fill="${color}" ${i===curIdx?'stroke="#fff" stroke-width="0.8"':''}/>`).join("");
  const ylab=v=> type==="pct"? Math.round(v*100)+"%" : (v>=1000? (Math.round(v/100)/10)+"k" : Math.round(v));
  const ylabs=`<text x="${PL-3}" y="${PT+6}" font-size="7.5" fill="#8aa0c4" text-anchor="end">${ylab(max)}</text><text x="${PL-3}" y="${PT+plotH}" font-size="7.5" fill="#8aa0c4" text-anchor="end">${ylab(min)}</text>`;
  const mlabels=months.map((m,i)=>`<text x="${X(i).toFixed(1)}" y="${H-5}" font-size="8" fill="#8aa0c4" text-anchor="middle">${m.replace("월","")}</text>`).join("");
  return `<svg class="chartanim" viewBox="0 0 ${W} ${H}" style="width:100%;height:auto;margin-top:6px">${grid}<polyline points="${areaPts}" fill="${color}" fill-opacity="0.12" stroke="none"/>${axes}${marker}<polyline points="${linePts}" fill="none" stroke="${color}" stroke-width="1.7" stroke-linejoin="round"/>${dots}${ylabs}${mlabels}</svg>`;
}
