  if(entityMode || ST.group==="개별"){
    isEntity=true; recsAll=DATA.records.filter(r=>r.name===name); const i=recsAll[0]||{};
    sub=`${i.gubun||""} · ${i.jipa||""} · ${CONT_KO[i.continent]||i.continent||"-"} ${i.country||""}`;
  }
  else if(ST.group==="대륙별"){ recsAll=DATA.records.filter(r=>contOf(r)===name && gf(r)); sub="대륙 합계"+(ST.gubun!=="전체"?` · ${ST.gubun}`:""); }
  else if(ST.group==="지파별"){ recsAll=DATA.records.filter(r=>r.jipa===name && gf(r)); sub=name+(ST.gubun==="전체"?" 전체(교회+지역+개척지)":` · ${ST.gubun}만`); }
  else { isEntity=true; recsAll=DATA.records.filter(r=>r.name===name); const i=recsAll[0]||{};
    sub=`${i.gubun||""} · ${i.jipa||""} · ${CONT_KO[i.continent]||i.continent||"-"} ${i.country||""}`; }
  const months=DATA.months;
  const perMonth={}; months.forEach(mn=>perMonth[mn]=aggregate(recsAll.filter(r=>r.month===mn)));
  const cur=perMonth[ST.month];
