// ── map ──
const MAP_W=1000, MAP_H=500;
const mapProj=(lat,lon)=>[ (lon+180)/360*MAP_W, (90-lat)/180*MAP_H ];
// minimal TopoJSON decoder
function tjDecodeArc(i){
  const arc=WORLD.arcs[i], s=WORLD.transform.scale, t=WORLD.transform.translate;
  let x=0,y=0; const out=[];
  for(const d of arc){ x+=d[0]; y+=d[1]; out.push([x*s[0]+t[0], y*s[1]+t[1]]); } // [lon,lat]
  return out;
}
const _arcCache={};
function tjArc(idx){
  if(idx>=0){ if(!_arcCache[idx])_arcCache[idx]=tjDecodeArc(idx); return _arcCache[idx]; }
  const k=~idx; if(!_arcCache[k])_arcCache[k]=tjDecodeArc(k); return _arcCache[k].slice().reverse();
}
function tjRing(ring){ let c=[]; ring.forEach((idx,k)=>{ let a=tjArc(idx); if(k>0)a=a.slice(1); c=c.concat(a); }); return c; }
function ringToPath(ring){ // ring = [[lon,lat],...] — 날짜변경선(±180°) 넘는 점프는 끊어서 가로 줄 방지
  let d="", prevX=null;
  for(const p of ring){
    const xy=mapProj(p[1],p[0]); const x=xy[0], y=xy[1];
    if(prevX===null || Math.abs(x-prevX)>MAP_W*0.5){ d+="M"+x.toFixed(1)+" "+y.toFixed(1); }
    else { d+="L"+x.toFixed(1)+" "+y.toFixed(1); }
    prevX=x;
  }
  return d+"Z";
}
let _landPaths=null;
function buildLandPaths(){
  if(_landPaths!=null) return _landPaths;
  let d="";
  WORLD.objects.countries.geometries.forEach(g=>{
    if(g.type==="Polygon"){ g.arcs.forEach(r=>d+=ringToPath(tjRing(r))); }
    else if(g.type==="MultiPolygon"){ g.arcs.forEach(poly=>poly.forEach(r=>d+=ringToPath(tjRing(r)))); }
  });
  _landPaths=d; return d;
}
// ISO numeric country code → 대륙 (데이터/기준표 분류에 맞춤: 러시아=유럽, 멕시코·중미=중앙아메리카)
const _CONT_CODES={
  "아시아":[4,51,31,48,50,64,96,116,156,268,356,360,364,368,376,392,400,398,414,417,418,422,458,462,496,104,524,408,512,586,275,608,634,682,702,410,144,760,158,762,764,626,792,795,784,860,704,887],
  "유럽":[8,40,112,56,70,100,191,196,203,208,233,246,250,276,300,348,352,372,380,428,440,442,470,498,499,528,807,578,616,620,642,643,688,703,705,724,752,756,804,826],
  "아프리카":[12,24,204,72,854,108,120,132,140,148,174,178,180,384,262,818,226,232,231,266,270,288,324,624,404,426,430,434,450,454,466,478,480,504,508,516,562,566,646,686,694,706,710,728,729,748,834,768,788,800,732,894,716],
  "북아메리카":[124,840,304],
  "중앙아메리카":[84,188,222,320,340,484,558,591,192,214,332,388,44,780,630],
  "남아메리카":[32,68,76,152,170,218,328,600,604,740,858,862,238],
  "오세아니아":[36,554,242,90,548,598,540]
};
const ISO_CONT={}; for(const c in _CONT_CODES){ _CONT_CODES[c].forEach(n=>{ISO_CONT[n]=c;}); }
let _landByCont=null;
function buildLandByCont(){
  if(_landByCont) return _landByCont;
  const groups={};
  WORLD.objects.countries.geometries.forEach(g=>{
    const cont=ISO_CONT[parseInt(g.id,10)]||"_default";
    let d="";
    if(g.type==="Polygon") g.arcs.forEach(r=>d+=ringToPath(tjRing(r)));
    else if(g.type==="MultiPolygon") g.arcs.forEach(poly=>poly.forEach(r=>d+=ringToPath(tjRing(r))));
    groups[cont]=(groups[cont]||"")+d;
  });
  _landByCont=groups; return groups;
}
function renderMap(){
  const recs=recordsFor(ST.month, ST.gubun).filter(r=>r.lat!=null && r.lon!=null);
  let g="";
  // ── 밝고 실제적인 지도: 파란 바다 + 자연 대지색 + 마커 글로우 ──
  g+=`<defs>
    <linearGradient id="oceanG" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="#e6eef4"/><stop offset="55%" stop-color="#d3e2ec"/><stop offset="100%" stop-color="#c0d6e4"/>
    </linearGradient>
    <filter id="mkGlow" x="-60%" y="-60%" width="220%" height="220%">
      <feDropShadow dx="0" dy="0.5" stdDeviation="0.7" flood-color="#2b3a54" flood-opacity="0.38"/>
    </filter>
  </defs>
  <rect x="0" y="0" width="${MAP_W}" height="${MAP_H}" fill="url(#oceanG)"/>`;
  // graticule (subtle)
  for(let lon=-180;lon<=180;lon+=30){ const [x]=mapProj(0,lon); g+=`<line x1="${x.toFixed(0)}" y1="0" x2="${x.toFixed(0)}" y2="${MAP_H}" stroke="rgba(70,120,170,.09)"/>`; }
  for(let lat=-60;lat<=80;lat+=30){ const [,y]=mapProj(lat,0); g+=`<line x1="0" y1="${y.toFixed(0)}" x2="${MAP_W}" y2="${y.toFixed(0)}" stroke="rgba(70,120,170,.09)"/>`; }
  // continents — 자연스러운 대지색(대륙별 은은한 차이)
  const lc=buildLandByCont();
  const CB={"아시아":"#dcdcc4","유럽":"#d7dcc2","아프리카":"#e2dabf","북아메리카":"#d6ddc6","중앙아메리카":"#d6ddc6","남아메리카":"#d2dbbe","오세아니아":"#dcd8bf"};
  g+=Object.keys(lc).map(c=>{ const col=(c==="_default")?"#d9dcc6":(CB[c]||"#d9dcc6");
    const fo = MAP_ZOOM ? (c===MAP_ZOOM?1:0.45) : 0.92;
    return `<path d="${lc[c]}" fill="${col}" fill-opacity="${fo}"/>`;
  }).join("");
  // 국경선 — 은은한 자연색
  g+=`<path d="${buildLandPaths()}" fill="none" stroke="#9ca485" stroke-opacity="${MAP_ZOOM?0.5:0.32}" stroke-width="0.4"/>`;
  // markers
  const mx=Math.max(1,...recs.map(r=>r.registered||0));
  recs.sort((a,b)=>(b.registered||0)-(a.registered||0));
  g+=`<g filter="url(#mkGlow)">`+recs.map(r=>{ if(MAP_FOCUS && r.name!==MAP_HL) return ""; const [x,y]=mapProj(r.lat,r.lon); const rad=2.5+Math.sqrt((r.registered||0)/mx)*15;
    const c=DATA.jipaColors[r.jipa]||"#888";
    const focus = !MAP_ZOOM || (CONT_KO[r.continent]||r.continent)===MAP_ZOOM;
    const fo=focus?0.9:0.16, sw=focus?'stroke="#ffffff" stroke-width="0.5" stroke-opacity="0.7"':'stroke-opacity="0"';
    return `<circle data-name="${encodeURIComponent(r.name)}" style="cursor:pointer" cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="${rad.toFixed(1)}" fill="${c}" fill-opacity="${fo}" ${sw}>
      <title>${r.name} (${r.jipa})&#10;${CONT_KO[r.continent]||r.continent||""} ${r.country||""}&#10;현재적 ${fmt(r.registered)}</title></circle>`;
  }).join("")+`</g>`;
  if(MAP_HL){ const hr=recs.find(r=>r.name===MAP_HL); if(hr&&hr.lat!=null){ const [hx,hy]=mapProj(hr.lat,hr.lon); const hrad=2.5+Math.sqrt((hr.registered||0)/mx)*15;
    g+=`<circle cx="${hx.toFixed(1)}" cy="${hy.toFixed(1)}" r="${(hrad+5).toFixed(1)}" fill="none" stroke="#ff2d55" stroke-width="2" pointer-events="none"><animate attributeName="r" values="${(hrad+2).toFixed(1)};${(hrad+14).toFixed(1)};${(hrad+2).toFixed(1)}" dur="1.3s" repeatCount="indefinite"/><animate attributeName="stroke-opacity" values="1;0.1;1" dur="1.3s" repeatCount="indefinite"/></circle>`; } }
  document.getElementById("map").innerHTML=g;
  const contLeg=Object.keys(_CONT_CODES).filter(c=>CONT_COLORS[c]).map(c=>
    `<span onclick="zoomMapTo('${c}')" title="${c}로 확대" style="font-size:12px;color:var(--muted);cursor:pointer;padding:3px 7px;border-radius:6px;transition:.12s" onmouseover="this.style.background='#eef3ff'" onmouseout="this.style.background='transparent'"><span style="display:inline-block;width:11px;height:11px;border-radius:3px;background:${CB[c]||'#8fb4e6'};margin-right:5px;vertical-align:middle"></span>${c}</span>`).join("");
  document.getElementById("maplegend").innerHTML=
    `<span style="font-size:11px;color:var(--muted);font-weight:700;margin-right:2px">대륙</span>`+contLeg+
    `<span style="color:var(--line);margin:0 5px">|</span><span style="font-size:11px;color:var(--muted)">● 점 = 지파색 · 크기=재적</span>`;
  const mi=document.getElementById("mapInfo"); if(mi && !mi.innerHTML.trim()) mi.innerHTML=PANEL_HINT;
  const sv=document.getElementById("map");
  if(MAP_NOSNAP){ const b=document.getElementById("mapResetBtn"); if(b) b.style.display="inline-block";
    const l=document.getElementById("mapZoomLabel"); if(l) l.textContent=`🔍 ${MAP_HL}`; }
  else if(MAP_FOCUS){ const [fx,fy]=mapProj(MAP_FOCUS.lat,MAP_FOCUS.lon); const FW=340,FH=170;
    sv.setAttribute("viewBox", `${(fx-FW/2).toFixed(1)} ${(fy-FH/2).toFixed(1)} ${FW} ${FH}`);
    const b=document.getElementById("mapResetBtn"); if(b) b.style.display="inline-block";
    const l=document.getElementById("mapZoomLabel"); if(l) l.textContent=`🔍 ${MAP_HL}`; }
  else if(MAP_ZOOM){ applyMapZoom(MAP_ZOOM); }
  else { sv.setAttribute("viewBox","0 0 1000 500");
    const b=document.getElementById("mapResetBtn"); if(b) b.style.display="none";
    const l=document.getElementById("mapZoomLabel"); if(l) l.textContent=""; }
}
let MAP_ZOOM=null;
function applyMapZoom(cont){
  const svg=document.getElementById("map");
  const recs=recordsFor(ST.month,ST.gubun).filter(r=>r.lat!=null&&r.lon!=null&&(CONT_KO[r.continent]||r.continent)===cont);
  if(!recs.length){ svg.setAttribute("viewBox","0 0 1000 500"); MAP_ZOOM=null;
    const b0=document.getElementById("mapResetBtn"); if(b0) b0.style.display="none";
    const l0=document.getElementById("mapZoomLabel"); if(l0) l0.textContent=""; return; }
  let minX=1e9,maxX=-1e9,minY=1e9,maxY=-1e9;
  recs.forEach(r=>{ const xy=mapProj(r.lat,r.lon); minX=Math.min(minX,xy[0]);maxX=Math.max(maxX,xy[0]);minY=Math.min(minY,xy[1]);maxY=Math.max(maxY,xy[1]); });
  let w=maxX-minX, h=maxY-minY;
  // 대륙별 확대 정도(여백비율/최소보기폭). 값이 작을수록 더 크게 확대.
  const PADF={"북아메리카":0.28,"중앙아메리카":0.28}, MINWS={"북아메리카":360,"중앙아메리카":320};
  const padF = (PADF[cont]!=null?PADF[cont]:0.5);
  const padX=Math.max(55,w*padF), padY=Math.max(55,h*padF);
  minX-=padX; maxX+=padX; minY-=padY; maxY+=padY; w=maxX-minX; h=maxY-minY;
  const MINW=(MINWS[cont]!=null?MINWS[cont]:500); if(w<MINW){ const cx=(minX+maxX)/2; minX=cx-MINW/2; w=MINW; }   // 최대 확대 제한
  if(w/h < 2){ const nw=h*2; minX-=(nw-w)/2; w=nw; } else { const nh=w/2; minY-=(nh-h)/2; h=nh; }
  svg.setAttribute("viewBox", `${minX.toFixed(1)} ${minY.toFixed(1)} ${w.toFixed(1)} ${h.toFixed(1)}`);
  const b=document.getElementById("mapResetBtn"); if(b) b.style.display="inline-block";
  const l=document.getElementById("mapZoomLabel"); if(l) l.textContent=`🔍 ${cont} 확대 중 (${recs.length}곳)`;
}
function zoomMapTo(cont){ MAP_ZOOM=cont; MAP_FOCUS=null; MAP_HL=null; renderMap(); }
function resetMapZoom(){ MAP_ZOOM=null; MAP_FOCUS=null; MAP_HL=null; renderMap(); }
let MAP_HL=null, MAP_FOCUS=null, MAP_NOSNAP=false;
// 현재 viewBox → 목표 viewBox 로 부드럽게 이동+줌 (팬+줌 동시, easeInOut)
function animateSvgViewBox(id,tgt,dur){ const sv=document.getElementById(id); if(!sv)return;
  const cur=(sv.getAttribute("viewBox")||"").trim().split(/\s+/).map(Number);
  if(cur.length!==4||cur.some(isNaN)){ sv.setAttribute("viewBox",tgt.map(n=>(+n).toFixed(1)).join(" ")); return; }
  const t0=performance.now(), D=dur||850;
  function step(t){ const k=Math.min(1,(t-t0)/D), e=k<0.5?2*k*k:1-Math.pow(-2*k+2,2)/2;
    sv.setAttribute("viewBox", cur.map((c,i)=>(c+(tgt[i]-c)*e).toFixed(1)).join(" "));
    if(k<1) requestAnimationFrame(step); }
  requestAnimationFrame(step);
}
function _searchSug(v,pickFn){
  const list=recordsFor(ST.month,"전체").filter(r=>r.lat!=null&&r.lon!=null&&((r.name||"").includes(v)||(r.country||"").includes(v))).slice(0,12);
  return list.length? list.map(r=>`<div onmousedown="${pickFn}('${(r.name||'').replace(/'/g,"\\'")}')" style="padding:8px 12px;cursor:pointer;border-bottom:1px solid #f0f3f8;font-size:13px" onmouseover="this.style.background='#eef3ff'" onmouseout="this.style.background='#fff'"><b>${r.name}</b> <span style="color:var(--muted);font-size:11.5px">· ${r.jipa||''} · ${fmt(r.registered)}명</span></div>`).join("")
    : `<div style="padding:9px 12px;color:var(--muted);font-size:13px">검색 결과 없음</div>`;
}
function mapSearchInput(){ const inp=document.getElementById("mapSearchInp"), sug=document.getElementById("mapSug"); if(!inp||!sug)return;
  const v=inp.value.trim(); if(!v){ sug.style.display="none"; return; } sug.innerHTML=_searchSug(v,"mapPick"); sug.style.display="block"; }
