const XLST_STATE={group:"지파별", gubun:"전체", sel:[], sort:null};
function xlsGroups(){
  const recs=recordsFor(ST.month, XLST_STATE.gubun);
  if(XLST_STATE.group==="대륙별"){ const m={}; recs.forEach(r=>{const k=contOf(r);(m[k]=m[k]||[]).push(r);}); return Object.entries(m).map(([k,v])=>({name:CONT_KO[k]||k,jipa:"",agg:aggregate(v)})).filter(g=>g.agg.count>0); }
  if(XLST_STATE.group==="교회별"){ return recs.filter(r=>r.gubun==="교회").map(r=>({name:r.name,jipa:r.jipa,agg:aggregate([r])})); }
  return DATA.jipaOrder.map(j=>({name:j,jipa:j,agg:aggregate(recs.filter(r=>r.jipa===j))})).filter(g=>g.agg.count>0);
}
function xlsBuildRows(){
  const sel=XLST_STATE.sel.map(l=>XLS_METRICS.find(m=>m.l===l)).filter(Boolean);
  let groups=xlsGroups();
  const sortM=XLS_METRICS.find(m=>m.l===XLST_STATE.sort);
  if(sortM) groups.sort((a,b)=>{ let va=sortM.f(a.agg), vb=sortM.f(b.agg); va=(va==null||isNaN(va))?-Infinity:va; vb=(vb==null||isNaN(vb))?-Infinity:vb; return vb-va; });
  const isCh=XLST_STATE.group==="교회별";
  const glabel=XLST_STATE.group==="대륙별"?"대륙":(isCh?"교회":"지파");
  const headers=["순위",glabel].concat(isCh?["지파"]:[]).concat(sel.map(m=>m.l));
  const rows=groups.map((g,i)=>{ const base=[{v:i+1,t:'num'},{v:g.name,t:'str'}]; if(isCh) base.push({v:g.jipa||'',t:'str'});
    return base.concat(sel.map(m=>{ let v=m.f(g.agg); const t=(m.t==='pct'?'pct':'num'); if(v==null||isNaN(v)) return {v:null,t}; return {v:(m.t==='pct'?v:Math.round(v)), t}; })); });
  return {headers,rows};
}
// --- 최소 .xlsx 생성기 (ZIP store + CRC32, 라이브러리 없이) ---
const _CRCT=(()=>{ const t=[]; for(let n=0;n<256;n++){ let c=n; for(let k=0;k<8;k++) c=(c&1)?(0xEDB88320^(c>>>1)):(c>>>1); t[n]=c>>>0; } return t; })();
