function hbarSVG(data){
  const max=Math.max(1,...data.map(d=>d.value||0));
  return `<div style="display:flex;flex-direction:column;gap:12px">`+data.map(d=>`
    <div style="display:grid;grid-template-columns:84px 1fr 52px;align-items:center;gap:9px">
      <span style="font-size:12px;color:#41506f;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${d.label}</span>
      <span style="height:15px;background:#eef2fa;border-radius:5px;overflow:hidden"><span class="gbar" style="display:block;height:100%;width:${(((d.value||0)/max)*100).toFixed(1)}%;background:${d.color||'#2563eb'};border-radius:5px"></span></span>
      <span style="font-size:12px;font-weight:800;text-align:right;color:#16224a;font-variant-numeric:tabular-nums">${fmt(d.value)}</span>
    </div>`).join("")+`</div>`;
}
function gaugeSVG(frac, label){
  const p=(frac==null||isNaN(frac))?0:Math.max(0,Math.min(1,frac));
  return `<div style="text-align:center">
    <div style="font-size:12px;color:#6b7a99;font-weight:700">${label||''}</div>
    <div style="font-size:44px;font-weight:900;color:#2563eb;letter-spacing:-1.5px;margin:8px 0 14px;font-variant-numeric:tabular-nums">${(p*100).toFixed(0)}%</div>
    <div style="height:13px;background:#eef2fa;border-radius:8px;overflow:hidden"><div class="gbar" style="height:100%;width:${(p*100).toFixed(1)}%;background:linear-gradient(90deg,#5fa8ff,#2563eb);border-radius:8px"></div></div>
  </div>`;
}
