function renderHome(){
  const recsAll=recordsFor(ST.month,"전체");
  const ch=recsAll.filter(r=>r.gubun==="교회");
  const reg=recsAll.filter(r=>r.gubun==="지역").length;
  const pio=recsAll.filter(r=>r.gubun==="개척지").length;
  const A=aggregate(recsAll);  // 교회·지역·개척지 모두 합산
  const newAtt=rate(A.newAttTotal,A.prevNewAdmitCnt), grad=rate(A.centerCumGrad,A.centerTotCumReg);
  const attRate=rate(A.attTotal,A.attReg);
  const regDiff=A.registered-A.prevReg, regRate=rate(regDiff,A.retroReg), admitRate=rate(A.newAdmit,A.retroReg);
  const kpis=[
    {l:"대상",v:`${ch.length+reg+pio}곳`,s:`교회 ${ch.length} · 지역 ${reg} · 개척지 ${pio}`,c:"var(--gold)",ic:"🏛️"},
    {l:"총 현재적",v:`${fmt(A.registered)}명`,s:`전월 대비 <span style="${regDiff<0?'color:#e1503e;font-weight:800':''}">${regDiff<0?`▼ ${fmt(Math.abs(regDiff))} · ▼ ${pct(Math.abs(regRate))}`:`${regDiff>=0?'+':''}${fmt(regDiff)} · ${pct(regRate)}`}</span>`,c:"#00a0e9",ic:"👥"},
    {l:"당월 입교",v:`${fmt(A.newAdmit)}명`,s:`입교율 ${pct(admitRate)}`,c:"#2ecc71",ic:"🌱"},
    {l:"전월입교자 예배출석",v:pct(newAtt),s:`실제 출석 ${fmt(A.newAttTotal)}명`,c:"#e39300",ic:"🙏"},
    {l:"센터 누적 종강",v:pct(grad),s:`누적 종강 ${fmt(A.centerCumGrad)}명`,c:"#7f1084",ic:"🎓"},
  ];
  const kpiHTML=kpis.map(k=>`<div class="kpi"><div class="k-bar" style="background:${k.c}"></div><div class="k-l">${k.l}</div><div class="k-v">${k.v}</div><div class="k-s">${k.s}</div></div>`).join("");
  // 6대륙 분포 (중앙아메리카→북아메리카 병합, 미분류 제외)
  const CONT6={"중앙아메리카":"북아메리카"};
  const cont6Color={"아시아":"#E8871E","유럽":"#F5C518","아프리카":"#6D28D9","북아메리카":"#2FA84F","남아메리카":"#E0447B","오세아니아":"#0EA5C4"};
  const contMap={}; recsAll.forEach(r=>{ const k0=contOf(r), k=CONT6[k0]||k0; if(k==="기타"||k==="미분류")return; contMap[k]=(contMap[k]||0)+(r.registered||0);});
  const donutData=Object.entries(contMap).map(([k,v])=>({label:k,value:v,color:cont6Color[k]||"#9aa8c4"})).sort((a,b)=>b.value-a.value);
  // 월별 추이들 (전 지파 합산)
  const months=DATA.months, aggByMonth=months.map(m=>aggregate(recordsFor(m,"전체")));
  const regTrend=aggByMonth.map(a=>a.registered);
  const admitTrend=aggByMonth.map(a=>a.newAdmit);
  const discipTrend=aggByMonth.map(a=>a.discipline);
  const attTrend=aggByMonth.map(a=>{const v=rate(a.attTotal,a.attReg); return v==null?0:+(v*100).toFixed(1);});
  const newAttTrend=aggByMonth.map(a=>{const v=rate(a.newAttTotal,a.prevNewAdmitCnt); return v==null?0:+(v*100).toFixed(1);});
  // 교회 재적 TOP5
  const top=ch.slice().sort((a,b)=>(b.registered||0)-(a.registered||0)).slice(0,5).map(r=>({label:r.name,value:r.registered||0,color:DATA.jipaColors[r.jipa]||"#2563eb"}));
  const bottom=ch.slice().sort((a,b)=>(a.registered||0)-(b.registered||0)).slice(0,5).reverse().map(r=>({label:r.name,value:r.registered||0,color:DATA.jipaColors[r.jipa]||"#2563eb"}));
  // 12지파 현황 매트릭스
  const maxJreg=Math.max(1,...DATA.jipaOrder.map(jp=>aggregate(recsAll.filter(r=>r.jipa===jp)).registered));
  const jrows=DATA.jipaOrder.map(jp=>{ const jr=recsAll.filter(r=>r.jipa===jp), a=aggregate(jr);
    return {jp, nCh:jr.filter(r=>r.gubun==="교회").length, nRg:jr.filter(r=>r.gubun==="지역").length, nPo:jr.filter(r=>r.gubun==="개척지").length,
      reg:a.registered, att:rate(a.attTotal,a.attReg), col:DATA.jipaColors[jp]||"#2563eb"}; });
  const jmxHTML=jrows.map(r=>`<div class="jmx-r">
    <span class="jp"><i style="background:${r.col}"></i>${r.jp}</span>
    <span class="num">${r.nCh}</span><span class="num">${r.nRg}</span><span class="num">${r.nPo}</span>
    <span class="mb"><span class="track"><span style="width:${(r.reg/maxJreg*100).toFixed(1)}%;background:${r.col}"></span></span><small>${fmt(r.reg)}</small></span>
    <span class="mb"><span class="track"><span style="width:${r.att==null?0:(r.att*100).toFixed(1)}%;background:${(r.att!=null&&r.att<0.8)?'#e11d48':'#2f80ed'}"></span></span><small>${pct(r.att)}</small></span>
  </div>`).join("");
  // 6월 특이사항 (자동 인사이트)
  const rcOf=r=>((+r.registered||0)-(+r.prevReg||0)); // 전월 대비 재적 변화(그 달 기준)
  const drops=recsAll.filter(r=>rcOf(r)<0).sort((a,b)=>rcOf(a)-rcOf(b)).slice(0,3);
  const gains=recsAll.filter(r=>rcOf(r)>0).sort((a,b)=>rcOf(b)-rcOf(a)).slice(0,2);
  const below95=recsAll.filter(r=>r.prevNewAdmitCnt>0 && (r.newAttTotal/r.prevNewAdmitCnt)<0.95);
  const noAdmitCh=ch.filter(r=>(r.newAdmit||0)===0).length;
  const insights=[];
  insights.push({c:"#2563eb",t:`총 현재적 <b>${fmt(A.registered)}명</b> · 전월 대비 <b>${regDiff>=0?'+':''}${fmt(regDiff)}</b> (${pct(regRate)})`});
  if(below95.length) insights.push({c:"#e1503e",t:`전월입교자 출석률 <b>95% 미만 ${below95.length}곳</b> — 질 점검 필요`});
  if(drops.length) insights.push({c:"#e1503e",t:`<b>재적 급감</b><br>${drops.map(d=>`${d.name} <b>${rcOf(d)}</b>`).join("<br>")}`});
  if(gains.length) insights.push({c:"#2f9e6e",t:`<b>재적 증가</b><br>${gains.map(d=>`${d.name} <b>+${rcOf(d)}</b>`).join("<br>")}`});
  insights.push({c:"#7a869e",t:`당월 입교 0인 교회 <b>${noAdmitCh}곳</b> · 당월 총 입교 ${fmt(A.newAdmit)}명`});
  const links=[["diag","교회 진단서"],["inspect","점검 (양·질)"],["funnel","전환율 퍼널"],["map","지도·지구본"],["trend","추이·비교"],["p1","전도·가개강"]];
  const html=`
    <div class="hero">
      <h1>전세계 12지파 해외교회의 현황을 한눈에</h1>
      <span class="spirit">✠ 양에 속지 말고 질을 보라 — 확인·점검에서 행함으로</span>
    </div>
    <div class="kpis k5">${kpiHTML}</div>
    <div class="card" style="margin-bottom:20px">
      <h3>12지파 현황판</h3>
      <div class="jmx-wrap"><div class="jmx">
        <div class="jmx-h"><span>지파</span><span class="num">교회</span><span class="num">지역</span><span class="num">개척</span><span>재적</span><span>전성도 출석률</span></div>
        ${jmxHTML}
      </div></div>
    </div>
    <div class="homerow">
      <div class="card"><h3>6대륙 현재적 분포</h3>${donutSVG(donutData,{})}</div>
      <div class="card"><h3>교회별 현재적 · TOP / BOTTOM 5</h3><div style="font-size:12px;font-weight:800;color:#2f80ed;margin:2px 0 8px">▲ TOP 5</div>${hbarSVG(top)}<div style="font-size:12px;font-weight:800;color:#e11d48;margin:16px 0 8px">▼ BOTTOM 5</div>${hbarSVG(bottom)}</div>
      <div class="card"><h3>🔎 ${ST.month} 특이사항</h3>${insights.map(s=>`<div class="ssum" style="border-left:3px solid ${s.c};padding-left:11px"><span>${s.t}</span></div>`).join("")}</div>
    </div>
    <div class="homerow">
      <div class="card"><h3>월별 현재적 추이</h3>${lineSVG(months,[{name:"현재적",color:"#2563eb",values:regTrend}])}</div>
      <div class="card"><h3>월별 입교 vs 사고</h3><div class="desc">입교(초록) · 사고(빨강)</div>${lineSVG(months,[{name:"입교",color:"#2ecc71",values:admitTrend},{name:"사고",color:"#e1503e",values:discipTrend}])}</div>
      <div class="card"><h3>예배자 출석율 (%)</h3><div class="desc">전성도(파랑) · 전월입교자(주황)</div>${lineSVG(months,[{name:"전성도",color:"#2563eb",values:attTrend},{name:"전월입교자",color:"#e39300",values:newAttTrend}])}</div>
    </div>`;
  document.getElementById("homeview").innerHTML=html;
}
// 🔮 현재적 예측 카드 (③내무 상단) — 실제+추정, 분기말 사고≈현재 관리불가 장기결석(리더 규칙)
function forecastCardHTML(){
  const fmA=DATA.months.map(m=>aggregate(recordsFor(m,"전체")).registered);
  const fmAd=DATA.months.map(m=>aggregate(recordsFor(m,"전체")).newAdmit);
  const L=DATA.months.length; if(L<2) return "";
  const avgAd=Math.round(fmAd.slice(-3).reduce((a,b)=>a+b,0)/Math.min(3,L));
  const curLU=aggregate(recordsFor(DATA.months[L-1],"전체")).absLongUnmanage;
  const smallDisc=150, base=fmA[L-1], lastNum=getMonthNumFromStr(DATA.months[L-1])||L;
  const fNums=[lastNum+1,lastNum+2,lastNum+3], fLab=fNums.map(n=>n+"월");
  const qmLab=fLab[fNums.findIndex(n=>n%3===0)];
  let prev=base; const fVals=fNums.map(n=>{ const d=(n%3===0)?curLU:smallDisc; prev=Math.round(prev+avgAd-d); return prev; });
  const labels=DATA.months.concat(fLab), act=fmA.concat([null,null,null]);
  const fore=DATA.months.map(()=>null); fore[L-1]=base; fVals.forEach(v=>fore.push(v));
  const all=act.concat(fore).filter(v=>v!=null), mn=Math.min(...all), mx=Math.max(...all), lo=mn-(mx-mn)*0.18||mn*0.98, hi=mx+(mx-mn)*0.18||mx*1.02;
  const W=940,H=250,PL=64,PR=18,PT=16,PB=42,pw=W-PL-PR,ph=H-PT-PB,N=labels.length;
  const X=i=>PL+pw*i/(N-1), Y=v=>PT+ph-((v-lo)/(hi-lo||1))*ph;
  let grid=""; for(let k=0;k<=3;k++){const gy=PT+ph*k/3,val=hi-(hi-lo)*k/3; grid+=`<line x1="${PL}" y1="${gy.toFixed(1)}" x2="${W-PR}" y2="${gy.toFixed(1)}" stroke="#e3eaf5"/><text x="${PL-7}" y="${(gy+3).toFixed(1)}" font-size="10.5" fill="#8aa0c4" text-anchor="end">${fmt(Math.round(val))}</text>`;}
  const fx0=X(L-1), region=`<rect x="${fx0.toFixed(1)}" y="${PT}" width="${(W-PR-fx0).toFixed(1)}" height="${ph}" fill="#fff6ee"/>`;
  let ad="",fd=""; act.forEach((v,i)=>{ if(v==null)return; ad+=(ad?'L':'M')+X(i).toFixed(1)+' '+Y(v).toFixed(1); });
  fore.forEach((v,i)=>{ if(v==null)return; fd+=(fd?'L':'M')+X(i).toFixed(1)+' '+Y(v).toFixed(1); });
  let pts=""; act.forEach((v,i)=>{ if(v==null)return; pts+=`<circle cx="${X(i).toFixed(1)}" cy="${Y(v).toFixed(1)}" r="3" fill="#fff" stroke="#2563eb" stroke-width="1.8"><title>${labels[i]}: ${fmt(v)}명</title></circle>`; });
  fVals.forEach((v,j)=>{ const i=L+j; pts+=`<circle cx="${X(i).toFixed(1)}" cy="${Y(v).toFixed(1)}" r="3.4" fill="#e0922e"><title>${labels[i]}(추정): ${fmt(v)}명</title></circle>`; });
  let xl=""; labels.forEach((l,i)=>{ xl+=`<text x="${X(i).toFixed(1)}" y="${H-18}" font-size="10.5" fill="${i>=L?'#e0922e':'#6b7a99'}" text-anchor="middle">${l}${i>=L?'*':''}</text>`; });
  const svg=`<svg class="chartanim" viewBox="0 0 ${W} ${H}" style="width:100%;height:auto">${region}${grid}<path d="${ad}" fill="none" stroke="#2563eb" stroke-width="2.6"/><path d="${fd}" fill="none" stroke="#e0922e" stroke-width="2.6" stroke-dasharray="6 4"/>${pts}${xl}</svg>`;
  const badges=fLab.map((l,j)=>{ const d=fVals[j]-(j?fVals[j-1]:base); return `<div><b style="color:#e0922e">${l}</b> 추정 <b>${fmt(fVals[j])}명</b> <span style="color:${d>=0?'#2f9e6e':'#e11d48'};font-weight:800">${d>=0?'▲ +':'▼ '}${fmt(Math.abs(d))}</span></div>`; }).join("");
  return `<div class="card" style="grid-column:1/-1"><h3>🔮 현재적 예측 (추정) — 향후 3개월</h3>
    <div class="desc"><span style="color:#2563eb;font-weight:800">파랑=실제</span> · <span style="color:#e0922e;font-weight:800">주황 점선=추정</span>. 가정: 최근 입교 <b>${fmt(avgAd)}명/월</b> 유입 지속 · 일반월 사고 소액 · <b>분기말(${qmLab}) 사고 ≈ 현재 관리불가 장기결석 ${fmt(curLU)}명</b>(리더 예측규칙). 개인추적 데이터 없어 <b>근사치</b>.</div>
    ${svg}
    <div style="display:flex;gap:20px;flex-wrap:wrap;margin-top:8px;font-size:13px">${badges}</div></div>`;
}
// ⚠️ 결석·사고 위험 표 (④예배·전성도 하단) — 관리불가 장기결석 → 다음 분기 사고 예측
function riskCardHTML(){
  const recs=recordsFor(ST.month,ST.gubun);
  const rrows=recs.map(r=>{ const a=aggregate([r]); return {name:r.name,jipa:r.jipa,color:DATA.jipaColors[r.jipa]||"#888",
    disc:a.discipline, lu:a.absLongUnmanage, lm:a.absLongManage, once:a.absOnce, absR:rate(a.absTotal,a.attReg)}; })
    .filter(x=> x.lu>0||x.lm>0||x.disc>0).sort((a,b)=> b.lu-a.lu || b.disc-a.disc).slice(0,15);
  const totDisc=recs.reduce((s,r)=>s+(+r.discipline||0),0), totLU=recs.reduce((s,r)=>s+(+r.absLongUnmanage||0),0), totLM=recs.reduce((s,r)=>s+(+r.absLongManage||0),0);
  const maxLU=Math.max(1,...rrows.map(x=>x.lu));
  const trs=rrows.map(x=>`<tr class="clk" data-name="${encodeURIComponent(x.name)}">
    <td class="name"><span class="dot" style="background:${x.color}"></span>${x.name}<div style="font-size:11px;color:var(--muted)">${x.jipa}</div></td>
    <td style="text-align:right;font-weight:800;color:${x.disc>0?'#e1503e':'var(--muted)'}">${fmt(x.disc)}</td>
    <td style="white-space:nowrap"><span style="display:inline-block;height:11px;border-radius:4px;background:#e11d48;width:${Math.round(x.lu/maxLU*80)}px;min-width:2px;vertical-align:middle"></span> <b>${fmt(x.lu)}</b></td>
    <td style="text-align:right;color:#e0922e">${fmt(x.lm)}</td>
    <td style="text-align:right;color:var(--muted)">${fmt(x.once)}</td>
    <td style="text-align:right">${x.absR==null?'-':pct(x.absR)}</td></tr>`).join("");
  return `<div class="card" style="grid-column:1/-1;min-width:0">
    <h3>⚠️ 결석·사고 위험 점검 — 관리불가 장기결석 → 다음 분기 사고 예측</h3>
    <div class="desc">${ST.month} · 구분 ${ST.gubun} · 사고는 분기(3·6·9·12월) 산출 · <b style="color:#e11d48">관리불가 장기결석</b>이 높은 곳이 다음 사고 위험 · 전체 사고 <b>${fmt(totDisc)}</b> · 관리불가 <b style="color:#e11d48">${fmt(totLU)}</b> · 관리가능 <b style="color:#e0922e">${fmt(totLM)}</b> · 관리불가 많은 순 상위 15곳</div>
    <div class="tblwrap" style="max-height:440px"><table>
      <thead><tr><th style="text-align:left">교회</th><th>사고(당월)</th><th>장기결석<br>관리불가</th><th>관리가능</th><th>일회성</th><th>결석율</th></tr></thead>
      <tbody>${trs||`<tr><td colspan="6" style="text-align:center;color:var(--muted);padding:20px">해당 데이터 없음</td></tr>`}</tbody>
    </table></div></div>`;
}
// ①~④ 인터랙티브 뷰: 상세표(항목 클릭=정렬+차트선택) + 지파/대륙(숫자=도넛·비율=막대) + 월별추이 + 순위막대
function renderP1(){
  const el=document.getElementById("secCharts"); if(!el) return;
  const mg=document.getElementById("mainGrid"); if(mg) mg.style.display="none";
  const cat=CATS[ST.cat]; if(!cat){ el.style.display="none"; return; }
  if(ST.sortIdx==null||ST.sortIdx<0||ST.sortIdx>cat.length){ const pi=cat.findIndex(m=>m.primary); ST.sortIdx=(pi>=0?pi+1:1); ST.sortDir=-1; }
  const si=ST.sortIdx, pm=cat[Math.max(0,si-1)];
  const recs=recordsFor(ST.month,ST.gubun), rows=buildRows();
  const gl=(ST.group==="개별"?(ST.gubun==="전체"?"대상":ST.gubun):ST.group.replace("별",""));
  const cols=[{l:gl,name:true},...cat.map(m=>({l:m.l,m}))];
  let tdata=rows.map(g=>({g,cells:cat.map(m=>metricVal(g.agg,m))}));
  tdata.sort((a,b)=>{ if(si===0){ if(ST.group==="지파별"){ return ST.sortDir*(DATA.jipaOrder.indexOf(a.g.name)-DATA.jipaOrder.indexOf(b.g.name)); } return ST.sortDir*(""+a.g.name).localeCompare(""+b.g.name,"ko");} let va=a.cells[si-1],vb=b.cells[si-1]; va=(va==null?-Infinity:va); vb=(vb==null?-Infinity:vb); return ST.sortDir*(va-vb); });
  const thead="<thead><tr>"+cols.map((c,i)=>`<th data-i="${i}" style="cursor:pointer${c.name?'':';min-width:92px;white-space:normal;vertical-align:bottom'}">${c.l}${i===si?(ST.sortDir<0?" ▼":" ▲"):""}</th>`).join("")+"</tr></thead>";
  const totAgg=aggregate(recs); // 상세표 하단 '계' 행 — 전체 합산(비율은 합산 분자·분모로 재계산)
  const totBase='position:sticky;bottom:0;background:#e9eef7;font-weight:800;border-top:2px solid #b9c8e2';
  const totRow=`<tr><td class="name" style="${totBase}">${tdata.length}${gl} 계</td>`+cat.map((m,j)=>{const v=metricVal(totAgg,m); const hi=(si>0&&j===si-1)?';background:#d5e2fb':''; return `<td style="${totBase}${hi}">${fmtVal(v,m)}</td>`;}).join("")+`</tr>`;
  const tbody="<tbody>"+tdata.map(d=>{const g=d.g; const sub=g.kind==="entity"?`<div style="font-size:11px;color:var(--muted)">${g.jipa} · ${g.continent||"-"}</div>`:""; return `<tr class="clk" data-name="${encodeURIComponent(g.name)}"><td class="name"><span class="dot" style="background:${g.color}"></span>${g.name}${sub}</td>`+cat.map((m,j)=>{const v=d.cells[j]; const hi=(si>0&&j===si-1)?' style="background:#eef4ff;font-weight:800"':''; return `<td${hi}>${fmtVal(v,m)}</td>`;}).join("")+`</tr>`;}).join("")+totRow+"</tbody>";
  const tableCard=`<div class="card" style="grid-column:1/-1;min-width:0"><h3>상세표 <span style="font-size:12px;font-weight:600;color:#8aa0c4">· 열 제목(항목)을 클릭하면 아래 차트가 그 항목 기준으로 바뀝니다 · 현재 <b style="color:#2563eb">${si>0?pm.l:'이름'}</b></span></h3>
    <div class="tblwrap" style="max-height:420px"><table id="p1tbl">${thead}${tbody}</table></div></div>`;
  const cpm=(si>0)?pm:(cat.find(m=>m.primary)||cat[0]), cIsPct=(cpm.t==="pct");
  const jvals=DATA.jipaOrder.map(j=>{const a=aggregate(recs.filter(r=>r.jipa===j)); return {label:j,value:metricVal(a,cpm),color:DATA.jipaColors[j]||"#888"};}).filter(d=>d.value!=null);
  const cmap={}; recs.forEach(r=>{const k=contOf(r); (cmap[k]=cmap[k]||[]).push(r);});
  const cvals=Object.entries(cmap).map(([k,rs])=>({label:k,value:metricVal(aggregate(rs),cpm),color:CONT_COLORS[k]||"#9aa8c4"})).filter(d=>d.value!=null);
  const empty='<div style="padding:28px 0;text-align:center;color:var(--muted);font-size:13px">데이터 없음</div>';
  const rateBar=(arr)=>{const mx=Math.max(0.0001,...arr.map(d=>Math.abs(d.value)||0)); return `<div style="display:flex;flex-direction:column;gap:7px;margin-top:6px">`+arr.slice().sort((a,b)=>b.value-a.value).map(d=>`<div style="display:grid;grid-template-columns:104px 1fr 56px;align-items:center;gap:9px"><span style="font-size:12px;font-weight:700;color:#41506f;white-space:nowrap"><span class="dot" style="background:${d.color}"></span>${d.label}</span><span style="height:15px;background:#eef2fa;border-radius:5px;overflow:hidden"><span class="gbar" style="display:block;height:100%;width:${(Math.abs(d.value)/mx*100).toFixed(1)}%;background:${d.color};border-radius:5px"></span></span><span style="font-size:12px;font-weight:800;text-align:right">${fmtVal(d.value,cpm)}</span></div>`).join("")+`</div>`;};
  const donutOrBar=(arr)=> !arr.length?empty:(cIsPct?rateBar(arr):(arr.filter(d=>d.value>0).length?donutSVG(arr.filter(d=>d.value>0).sort((a,b)=>b.value-a.value),{}):empty));
  const jCard=`<div class="card"><h3>지파별 ${cpm.l}</h3>${donutOrBar(jvals)}</div>`;
  const cCard=`<div class="card"><h3>대륙별 ${cpm.l}</h3>${donutOrBar(cvals)}</div>`;
  const mo=DATA.months, lv=mo.map(m=>{const v=metricVal(aggregate(recordsFor(m,ST.gubun)),cpm); return v==null?0:(cIsPct?+(v*100).toFixed(1):v);});
  const trendCard=`<div class="card"><h3>월별 ${cpm.l} 추이</h3>${lineSVG(mo,[{name:cpm.l,color:"#2563eb",values:lv}])}</div>`;
  const chData=rows.map(g=>({...g,val:metricVal(g.agg,cpm)})).filter(g=>g.val!=null).sort((a,b)=>b.val-a.val);
  const chMax=Math.max(0.0001,...chData.map(d=>Math.abs(d.val)||0));
  const chBars=`<div style="display:flex;flex-direction:column;gap:8px;max-height:520px;overflow-y:auto;padding-right:6px;margin-top:6px">`+chData.map(d=>`<div class="brow" data-name="${encodeURIComponent(d.name)}"><div class="bname" title="${d.name}"><span class="dot" style="background:${d.color}"></span>${d.name}</div><div class="btrack"><div class="bfill" style="width:${Math.max(2,Math.abs(d.val)/chMax*100)}%;background:${d.color}"></div></div><div class="bval">${fmtVal(d.val,cpm)}</div></div>`).join("")+`</div>`;
  const barCard=`<div class="card"><h3>${gl}별 ${cpm.l} 순위</h3>${chData.length?chBars:empty}</div>`;
  el.style.gridTemplateColumns="minmax(0,1fr) minmax(0,1fr)";
  el.innerHTML=tableCard+jCard+barCard+cCard+trendCard+(ST.cat==="③내무"?forecastCardHTML():"")+(ST.cat==="④예배·결석"?riskCardHTML():"");
  el.style.display="grid";
  el.querySelectorAll("#p1tbl th").forEach(th=>th.onclick=()=>{ const i=+th.dataset.i; if(ST.sortIdx===i){ST.sortDir*=-1;}else{ST.sortIdx=i;ST.sortDir=(i===0?1:-1);} render(); });
  el.querySelectorAll("#p1tbl tr.clk, .brow").forEach(x=>x.onclick=()=>openDetail(decodeURIComponent(x.dataset.name)));
}
// 신앙 프로세스 섹션 상단 차트(지파별·대륙별 도넛 + 월별 추이) — mockup 04·05
