// ── 인트로(랜딩) ──
function initIntro(){
  const enter=async ()=>{
    const s=document.getElementById("introScreen"); if(!s)return;
    const p=document.getElementById("introPw"), field=document.querySelector(".in-field"), err=document.getElementById("introErr");
    const val=p?p.value.trim():"";
    
    if (typeof ENCRYPTED_DATA !== "undefined" && ENCRYPTED_DATA) {
      try {
        const decryptedStr = await decryptData(ENCRYPTED_DATA, val);
        window.DATA = JSON.parse(decryptedStr);
        DATA = window.DATA;
        buildUI();
        render();
      } catch (e) {
        const L=ST.diagLang||"ko";
        if(err){ err.textContent=(UI_TR.pwErr[L]||UI_TR.pwErr.ko); err.classList.add("on"); }
        if(field){ field.classList.add("bad","shake"); setTimeout(()=>field.classList.remove("shake"),450); }
        if(p){ p.value=""; p.focus(); }
        return;
      }
    } else {
      if(val!==ACCESS_PW){
        const L=ST.diagLang||"ko";
        if(err){ err.textContent=(UI_TR.pwErr[L]||UI_TR.pwErr.ko); err.classList.add("on"); }
        if(field){ field.classList.add("bad","shake"); setTimeout(()=>field.classList.remove("shake"),450); }
        if(p){ p.value=""; p.focus(); }
        return;
      }
    }
    
    if(err) err.classList.remove("on"); if(field) field.classList.remove("bad");
    s.classList.add("hide");
  };
  window.showIntro=()=>{ const s=document.getElementById("introScreen"); if(!s)return; s.classList.remove("hide"); const p=document.getElementById("introPw"); if(p){ p.value=""; setTimeout(()=>p.focus(),450);} const err=document.getElementById("introErr"); if(err)err.classList.remove("on"); const field=document.querySelector(".in-field"); if(field)field.classList.remove("bad"); };
  const btn=document.getElementById("introEnter"), pw=document.getElementById("introPw"), eye=document.getElementById("introEye");
  if(btn) btn.onclick=enter;
  if(pw) pw.addEventListener("keydown",e=>{ if(e.key==="Enter") enter(); });
  if(eye) eye.onclick=()=>{ if(pw) pw.type=(pw.type==="password"?"text":"password"); };
  // 라이브 통계 + 전체 정적 문구를 현재 언어로 주입
  applyStaticLang();
  if(pw) setTimeout(()=>pw.focus(),400);
  if (typeof IS_SHARE_FILE !== "undefined" && IS_SHARE_FILE) {
    document.body.classList.add("share-mode");
  }
  if (typeof ACCESS_PW === "undefined" || !ACCESS_PW) {
    const s = document.getElementById("introScreen");
    if(s) s.classList.add("hide");
  }
}

