async function encryptData(plaintext, password) {
  const enc = new TextEncoder();
  const salt = window.crypto.getRandomValues(new Uint8Array(16));
  const pbkdf2Key = await window.crypto.subtle.importKey(
    "raw", enc.encode(password), { name: "PBKDF2" }, false, ["deriveKey"]
  );
  const key = await window.crypto.subtle.deriveKey(
    { name: "PBKDF2", salt: salt, iterations: 100000, hash: "SHA-256" },
    pbkdf2Key, { name: "AES-GCM", length: 256 }, false, ["encrypt"]
  );
  const iv = window.crypto.getRandomValues(new Uint8Array(12));
  const encrypted = await window.crypto.subtle.encrypt(
    { name: "AES-GCM", iv: iv }, key, enc.encode(plaintext)
  );
  const combined = new Uint8Array(salt.length + iv.length + encrypted.byteLength);
  combined.set(salt, 0);
  combined.set(iv, salt.length);
  combined.set(new Uint8Array(encrypted), salt.length + iv.length);
  return btoa(String.fromCharCode.apply(null, combined));
}

async function decryptData(ciphertextBase64, password) {
  const combined = new Uint8Array(atob(ciphertextBase64).split("").map(c => c.charCodeAt(0)));
  const salt = combined.slice(0, 16);
  const iv = combined.slice(16, 28);
  const encrypted = combined.slice(28);
  
  const enc = new TextEncoder();
  const pbkdf2Key = await window.crypto.subtle.importKey(
    "raw", enc.encode(password), { name: "PBKDF2" }, false, ["deriveKey"]
  );
  const key = await window.crypto.subtle.deriveKey(
    { name: "PBKDF2", salt: salt, iterations: 100000, hash: "SHA-256" },
    pbkdf2Key, { name: "AES-GCM", length: 256 }, false, ["decrypt"]
  );
  const decrypted = await window.crypto.subtle.decrypt(
    { name: "AES-GCM", iv: iv }, key, encrypted
  );
  return new TextDecoder().decode(decrypted);
}

window.generateShareFile = async () => {
  const status = document.getElementById("shareStatus");
  const select = document.getElementById("shareEntitySelect");
  const pwInput = document.getElementById("sharePassword");
  
  if (!select || !window.DATA) return;
  const selectedName = select.value;
  const password = pwInput ? pwInput.value.trim() : "";
  
  if (status) {
    status.className = "share-status-msg info";
    status.textContent = "공유용 HTML 파일 생성 중...";
  }
  
  try {
    const filteredRecords = window.DATA.records.filter(r => r.name === selectedName);
    const sharedData = {
      months: window.DATA.months,
      jipaOrder: window.DATA.jipaOrder,
      jipaColors: window.DATA.jipaColors,
      records: filteredRecords
    };
    
    const dataString = JSON.stringify(sharedData);
    
    let templateHtml = "";
    try {
      templateHtml = await fetch(window.location.href).then(res => res.text());
    } catch (e) {
      console.warn("Fetch failed, falling back to outerHTML:", e);
      templateHtml = "<!DOCTYPE html>\n<html lang=\"" + document.documentElement.lang + "\">" + document.documentElement.innerHTML + "</html>";
    }
    
    let dataScriptTag = "";
    if (password) {
      const encryptedBase64 = await encryptData(dataString, password);
      dataScriptTag = `<script>
        const ENCRYPTED_DATA = "${encryptedBase64}";
        const ACCESS_PW = "HAS_PASSWORD";
        const IS_SHARE_FILE = true;
      <\/script>`;
    } else {
      dataScriptTag = `<script>
        window.DATA = ${dataString};
        const ACCESS_PW = "";
        const IS_SHARE_FILE = true;
      <\/script>`;
    }
    
    // Replace script reference to data.js with the inline data script using RegExp string constructors (safe from early tag closure)
    templateHtml = templateHtml.replace(new RegExp("<script\\\\s+src=\"data\\\\.js\"\\\\s*><\\\\/script>", "i"), dataScriptTag);
    
    // Ensure the share modal is closed/hidden in the exported file
    templateHtml = templateHtml.replace(new RegExp('id="shareModal"\\\\s+class="share-modal-overlay[^\"]*"', 'i'), 'id="shareModal" class="share-modal-overlay hide"');
    
    // Clean body classes to reset it in the exported file
    templateHtml = templateHtml.replace(new RegExp('<body\\\\s+class="[^\"]*"', 'i'), "<body>");
    
    const blob = new Blob([templateHtml], { type: "text/html" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `진단서-${selectedName}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    
    if (status) {
      status.className = "share-status-msg success";
      status.textContent = `성공! 진단서-${selectedName}.html 파일이 다운로드 폴더에 생성되었습니다.`;
    }
    
    setTimeout(() => {
      closeShareModal();
    }, 1500);
    
  } catch (err) {
    console.error(err);
    if (status) {
      status.className = "share-status-msg error";
      status.textContent = "파일 생성 중 오류가 발생했습니다: " + err.message;
    }
  }
};
// ── 인트로 국기 회전 지구본 ──
function initFlagGlobe(){
  const cv=document.getElementById('flagGlobe'); if(!cv||!window.FLAGIMG) return;
  const IMG=window.FLAGIMG, codes=Object.keys(IMG); if(!codes.length) return;
  const imgs=[]; let done=0;
  codes.forEach(c=>{ const im=new Image(); im.onload=im.onerror=()=>{ if(++done===codes.length) start(); }; im.src=IMG[c]; imgs.push(im); });
  const SZ=600, cx=SZ/2, cy=SZ/2, R=SZ/2-10, TW=1400, TH=700, N=SZ*SZ;
  const mask=new Uint8Array(N), lonBase=new Float32Array(N), vRow=new Int32Array(N), shade=new Float32Array(N), spec=new Float32Array(N);
  let texData=null, ctx=null, out=null; const cols=22, rows=14;
  function rrect(t,x,y,w,h,r){ t.beginPath(); t.moveTo(x+r,y); t.arcTo(x+w,y,x+w,y+h,r); t.arcTo(x+w,y+h,x,y+h,r); t.arcTo(x,y+h,x,y,r); t.arcTo(x,y,x+w,y,r); t.closePath(); }
  function buildTexture(){
    const tc=document.createElement('canvas'); tc.width=TW; tc.height=TH; const t=tc.getContext('2d');
    t.fillStyle='#eef2f7'; t.fillRect(0,0,TW,TH);
    const cw=TW/cols, ch=TH/rows, g=Math.min(cw,ch)*0.13;
    const seq=[]; let pool=[];
    for(let i=0;i<cols*rows;i++){ if(!pool.length) pool=imgs.slice().sort(()=>Math.random()-0.5); seq.push(pool.pop()); }
    let k=0;
    for(let r=0;r<rows;r++) for(let c=0;c<cols;c++){
      const im=seq[k++], x=c*cw+g/2, y=r*ch+g/2, w=cw-g, h=ch-g, rad=Math.min(w,h)*0.15;
      t.save(); t.shadowColor='rgba(20,36,74,.35)'; t.shadowBlur=4; t.shadowOffsetY=2; t.fillStyle='#fff'; rrect(t,x,y,w,h,rad); t.fill(); t.restore();
      t.save(); rrect(t,x,y,w,h,rad); t.clip(); try{ t.drawImage(im,x,y,w,h); }catch(e){} t.restore();
      t.save(); rrect(t,x+0.6,y+0.6,w-1.2,h-1.2,rad); t.strokeStyle='rgba(255,255,255,.6)'; t.lineWidth=1; t.stroke(); t.restore();
    }
    texData=t.getImageData(0,0,TW,TH).data;
  }
  function precompute(){
    const Lx=-0.38, Ly=0.44, Lz=0.81, Ln=Math.hypot(Lx,Ly,Lz), lx=Lx/Ln, ly=Ly/Ln, lz=Lz/Ln;
    for(let py=0;py<SZ;py++) for(let px=0;px<SZ;px++){
      const idx=py*SZ+px, x=(px+0.5-cx)/R, y=(py+0.5-cy)/R, d2=x*x+y*y;
      if(d2>1){ mask[idx]=0; continue; }
      mask[idx]=1; const z=Math.sqrt(1-d2), nx=x, ny=-y, nz=z, lat=Math.asin(ny);
      lonBase[idx]=Math.atan2(nx,nz);
      let vy=(1-(lat/Math.PI+0.5))*(TH-1); vRow[idx]=vy<0?0:(vy>TH-1?TH-1:vy|0);
      const diff=Math.max(0, nx*lx+ny*ly+nz*lz);
      shade[idx]=(0.6+0.5*diff)*(0.82+0.18*nz); spec[idx]=Math.pow(diff,14)*66;
    }
  }
  function render(off){
    const p=out.data;
    for(let idx=0,o=0; idx<N; idx++, o+=4){
      if(!mask[idx]){ p[o+3]=0; continue; }
      let u=(lonBase[idx]+off)/(2*Math.PI)+0.5; u-=Math.floor(u);
      const ti=(vRow[idx]*TW+((u*TW)|0))*4, s=shade[idx], sp=spec[idx];
      let r=texData[ti]*s+sp, g=texData[ti+1]*s+sp, b=texData[ti+2]*s+sp;
      p[o]=r>255?255:r; p[o+1]=g>255?255:g; p[o+2]=b>255?255:b; p[o+3]=255;
    }
    ctx.putImageData(out,0,0);
  }
  let off=0;
  function loop(){ off+=0.0024; render(off); requestAnimationFrame(loop); }
  function start(){ ctx=cv.getContext('2d'); out=ctx.createImageData(SZ,SZ); buildTexture(); precompute(); loop(); }
}

window.startDiagnosisApp = function() {
  try {
    const userStr = localStorage.getItem('user');
    if (userStr && window.DATA && window.DATA.records) {
      const u = JSON.parse(userStr);
      const role = u.role || 'ROLE_USER';
      const assignedLocation = u.assignedCountry || '전체';
      if (role !== 'ROLE_ADMIN' && role !== 'ADMIN' && role !== '관리자' && assignedLocation !== '전체') {
        window.DATA.records = window.DATA.records.filter(r =>
          r.name === assignedLocation ||
          r.country === assignedLocation ||
          (r.jipa + ' · ' + r.name) === assignedLocation
        );
      }
    }
  } catch(e){}

  try { if (typeof buildUI === 'function') buildUI(); } catch(e){ console.warn(e); }
  try { if (typeof render === 'function') render(); } catch(e){ console.warn(e); }
  try { if (typeof initIntro === 'function') initIntro(); } catch(e){ console.warn(e); }
  try { if (typeof initFlagGlobe === 'function') initFlagGlobe(); } catch(e){ console.warn(e); }
};


// ── 맨 위로 버튼 ──
function goTop(){ window.scrollTo({top:0, behavior:'smooth'}); }
(function(){
  function upd(){
    var btn=document.getElementById('toTop');
    if(btn) {
      if(window.scrollY>300) btn.classList.add('show'); else btn.classList.remove('show');
    }
  }
  window.addEventListener('scroll', upd, {passive:true});
})();
